==========
Here's a **complete HTML and JavaScript implementation of a simplified version of Space Invaders**. This version includes:

- A player-controlled spaceship (left/right movement)
- Shooting bullets
- Falling alien invaders
- Basic collision detection
- Game over and win conditions

You can copy and paste this into a `.html` file and open it in your browser.

---

### ✅ Full Space Invaders Game (HTML + JavaScript)

```html
<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <title>Space Invaders</title>
  <style>
    body {
      margin: 0;
      background: black;
      color: white;
      font-family: sans-serif;
      display: flex;
      flex-direction: column;
      align-items: center;
      justify-content: center;
      height: 100vh;
      overflow: hidden;
    }
    canvas {
      background: #000;
      border: 2px solid #fff;
    }
    #gameOver {
      display: none;
      font-size: 2em;
      color: red;
    }
  </style>
</head>
<body>
  <canvas id="gameCanvas" width="600" height="800"></canvas>
  <div id="gameOver">Game Over</div>
  <script>
    const canvas = document.getElementById("gameCanvas");
    const ctx = canvas.getContext("2d");

    const player = {
      x: canvas.width / 2 - 25,
      y: canvas.height - 60,
      width: 50,
      height: 30,
      speed: 5,
      color: "lime"
    };

    const bullets = [];
    const aliens = [];
    const alienBullets = [];

    let rightPressed = false;
    let leftPressed = false;
    let shootInterval = 0;
    let alienDirection = 1;
    let alienSpeed = 1;
    let alienDropAmount = 15;
    let alienMoveTimer = 0;
    let alienShootTimer = 0;
    let gameOver = false;
    let score = 0;

    const alienRows = 5;
    const alienCols = 10;
    const alienPadding = 30;

    // Initialize aliens
    function initAliens() {
      aliens.length = 0;
      for (let r = 0; r < alienRows; r++) {
        for (let c = 0; c < alienCols; c++) {
          aliens.push({
            x: c * alienPadding + 50,
            y: r * alienPadding + 50,
            width: 30,
            height: 20,
            alive: true
          });
        }
      }
    }

    // Draw player
    function drawPlayer() {
      ctx.fillStyle = player.color;
      ctx.fillRect(player.x, player.y, player.width, player.height);
    }

    // Draw bullets
    function drawBullets() {
      ctx.fillStyle = "white";
      for (let b of bullets) {
        ctx.fillRect(b.x, b.y, b.width, b.height);
      }
    }

    // Draw aliens
    function drawAliens() {
      for (let a of aliens) {
        if (!a.alive) continue;
        ctx.fillStyle = "red";
        ctx.fillRect(a.x, a.y, a.width, a.height);
      }
    }

    // Draw alien bullets
    function drawAlienBullets() {
      ctx.fillStyle = "yellow";
      for (let b of alienBullets) {
        ctx.fillRect(b.x, b.y, b.width, b.height);
      }
    }

    // Collision detection
    function rectCollide(a, b) {
      return (
        a.x < b.x + b.width &&
        a.x + a.width > b.x &&
        a.y < b.y + b.height &&
        a.y + a.height > b.y
      );
    }

    // Update game logic
    function update() {
      if (gameOver) return;

      // Player movement
      if (rightPressed && player.x + player.width < canvas.width) {
        player.x += player.speed;
      }
      if (leftPressed && player.x > 0) {
        player.x -= player.speed;
      }

      // Shooting
      shootInterval++;
      if (shootInterval % 10 === 0) {
        bullets.push({
          x: player.x + player.width / 2 - 2,
          y: player.y,
          width: 4,
          height: 10
        });
      }

      // Alien movement
      alienMoveTimer++;
      if (alienMoveTimer % 30 === 0) {
        let moveDown = false;
        for (let a of aliens) {
          if (!a.alive) continue;
          a.x += alienDirection * alienSpeed;
          if (a.x + a.width >= canvas.width || a.x <= 0) {
            moveDown = true;
          }
        }
        if (moveDown) {
          alienDirection *= -1;
          for (let a of aliens) {
            if (a.alive) a.y += alienDropAmount;
          }
        }
      }

      // Alien shooting
      alienShootTimer++;
      if (alienShootTimer % 60 === 0) {
        for (let a of aliens) {
          if (!a.alive) continue;
          alienBullets.push({
            x: a.x + a.width / 2 - 2,
            y: a.y + a.height,
            width: 4,
            height: 10
          });
        }
      }

      // Update bullets
      for (let i = bullets.length - 1; i >= 0; i--) {
        bullets[i].y -= 6;
        if (bullets[i].y < 0) {
          bullets.splice(i, 1);
        }
      }

      // Update alien bullets
      for (let i = alienBullets.length - 1; i >= 0; i--) {
        alienBullets[i].y += 4;
        if (alienBullets[i].y > canvas.height) {
          alienBullets.splice(i, 1);
        }
      }

      // Collision: bullet vs alien
      for (let i = bullets.length - 1; i >= 0; i--) {
        let hit = false;
        for (let a of aliens) {
          if (!a.alive) continue;
          if (rectCollide(bullets[i], a)) {
            a.alive = false;
            bullets.splice(i, 1);
            score += 10;
            hit = true;
            break;
          }
        }
        if (hit) break;
      }

      // Collision: alien bullet vs player
      for (let i = alienBullets.length - 1; i >= 0; i--) {
        if (rectCollide(alienBullets[i], player)) {
          gameOver = true;
          document.getElementById("gameOver").style.display = "block";
          return;
        }
      }

      // Check win condition
      let allDead = true;
      for (let a of aliens) {
        if (a.alive) {
          allDead = false;
          break;
        }
      }
      if (allDead) {
        gameOver = true;
        document.getElementById("gameOver").innerText = "You Win!";
        document.getElementById("gameOver").style.display = "block";
      }
    }

    // Render game
    function render() {
      ctx.clearRect(0, 0, canvas.width, canvas.height);
      drawPlayer();
      drawBullets();
      drawAliens();
      drawAlienBullets();
    }

    // Game loop
    function gameLoop() {
      update();
      render();
      if (!gameOver) {
        requestAnimationFrame(gameLoop);
      }
    }

    // Event listeners
    document.addEventListener("keydown", (e) => {
      if (e.key === "ArrowRight") rightPressed = true;
      if (e.key === "ArrowLeft") leftPressed = true;
      if (e.key === " " || e.key === "ArrowUp") {
        e.preventDefault();
        // Manual shoot
        bullets.push({
          x: player.x + player.width / 2 - 2,
          y: player.y,
          width: 4,
          height: 10
        });
      }
    });

    document.addEventListener("keyup", (e) => {
      if (e.key === "ArrowRight") rightPressed = false;
      if (e.key === "ArrowLeft") leftPressed = false;
    });

    // Start game
    initAliens();
    gameLoop();
  </script>
</body>
</html>
```

---

### 🕹️ Controls:

- **Left Arrow** / **A**: Move left
- **Right Arrow** / **D**: Move right
- **Space** / **Up Arrow**: Shoot

---

### 🧠 Features Implemented:

- Player movement and shooting
- Alien movement (side to side and down)
- Alien shooting
- Collision detection (bullets destroy aliens, alien bullets kill player)
- Win/lose conditions
- Score tracking

